/**
 * Convert a plain object to FormData.
 * The FriendLinq Node.js backend expects ALL requests as multipart/form-data,
 * matching the mobile app's post_services.js which wraps everything in FormData.
 */
export const toFormData = (obj) => {
  const formData = new FormData();
  if (obj && typeof obj === 'object') {
    Object.keys(obj).forEach((key) => {
      if (obj[key] !== undefined && obj[key] !== null) {
        formData.append(key, obj[key]);
      }
    });
  }
  return formData;
};

/**
 * POST with FormData to Node.js API (matching mobile app's post_services.js)
 */
export const postFormData = (apiInstance, url, params) => {
  const formData = toFormData(params);
  return apiInstance.post(url, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  });
};
