import { nodeApi, dotnetApi } from '../axios';
import { ENDPOINTS } from '../config';
import { postFormData } from '../helpers';

// Node.js backend requires ALL requests as POST with FormData
// (matching mobile app's post_services.js)
const postService = {
  createPost: (formData) => nodeApi.post(ENDPOINTS.CREATE_POST, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  getMyPosts: (params) => postFormData(nodeApi, ENDPOINTS.GET_MY_POSTS, params),
  deletePost: (params) => postFormData(nodeApi, ENDPOINTS.DELETE_POST, params),
  editPost: (formData) => nodeApi.post(ENDPOINTS.EDIT_POST, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  getPostDetail: (params) => postFormData(nodeApi, ENDPOINTS.POST_DETAIL, params),
  getOtherUserPosts: (params) => postFormData(nodeApi, ENDPOINTS.GET_OTHER_POSTS, params),
  getFriendsPosts: (params) => postFormData(nodeApi, ENDPOINTS.GET_FRIENDS_POSTS, params),
  getPublicPosts: (params) => dotnetApi.get(ENDPOINTS.PUBLIC_POSTS, { params }),
  sharePost: (data) => dotnetApi.post(ENDPOINTS.SHARE_POST, data),
  likeUnlike: (params) => postFormData(nodeApi, ENDPOINTS.LIKE_UNLIKE, params),
  dislike: (params) => postFormData(nodeApi, ENDPOINTS.DISLIKE, params),
  updateSensitivity: (data) => dotnetApi.post(ENDPOINTS.UPDATE_SENSITIVITY, data),
  commentOnOff: (params) => postFormData(nodeApi, ENDPOINTS.COMMENT_ON_OFF, params),

  // Comments
  postComment: (params) => postFormData(nodeApi, ENDPOINTS.POST_COMMENT, params),
  getComments: (params) => postFormData(nodeApi, ENDPOINTS.GET_COMMENTS, params),
  deleteComment: (params) => postFormData(nodeApi, ENDPOINTS.DELETE_COMMENT, params),
  editComment: (params) => postFormData(nodeApi, ENDPOINTS.EDIT_COMMENT, params),
};

export default postService;
