import { useEffect } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { loadProfile } from '../redux/thunks/authThunks';
import { fetchFriendRequests } from '../redux/thunks/friendThunks';
import { fetchUnreadCount } from '../redux/thunks/chatThunks';
import { fetchNotifications } from '../redux/thunks/notificationThunks';
import { connectSocket } from '../api/socket';

const useInitialData = () => {
  const { isAuthenticated, user, token } = useSelector((state) => state.auth);
  const dispatch = useDispatch();

  useEffect(() => {
    if (isAuthenticated && token) {
      // Load fresh profile data
      dispatch(loadProfile());
      // Load friend requests for badge count
      dispatch(fetchFriendRequests({ skip: 0, limit: 50 }));
      // Load unread chat count for badge
      dispatch(fetchUnreadCount());
      // Load notifications for badge count
      dispatch(fetchNotifications({ skip: 0, limit: 30 }));
      // Connect socket
      if (user?._id) {
        connectSocket(user._id);
      }
    }
  }, [isAuthenticated, token, user?._id, dispatch]);
};

export default useInitialData;
