import { createAsyncThunk } from '@reduxjs/toolkit';
import postService from '../../api/services/postService';

export const fetchFeedPosts = createAsyncThunk(
  'posts/fetchFeed',
  async ({ skip = 0, limit = 20 }, { rejectWithValue }) => {
    try {
      const response = await postService.getFriendsPosts({ skip, limit });
      return { posts: response.data.data || [], skip };
    } catch (error) {
      return rejectWithValue(error.response?.data?.message || 'Failed to load feed');
    }
  }
);

