import { createSlice } from '@reduxjs/toolkit';
import {
  fetchChatList, fetchMessages, sendTextMessage,
  sendMediaMessage, markChatRead, deleteChatMessage,
  fetchUnreadCount,
} from '../thunks/chatThunks';

const initialState = {
  chatList: [],
  currentMessages: [],
  currentRecipientId: null,
  unreadCount: 0,
  hasMoreMessages: true,
  loading: false,
  listLoading: false,
  sending: false,
  error: null,
};

const chatSlice = createSlice({
  name: 'chat',
  initialState,
  reducers: {
    resetChat: () => initialState,
    clearCurrentChat: (state) => {
      state.currentMessages = [];
      state.currentRecipientId = null;
      state.hasMoreMessages = true;
    },
    addIncomingMessage: (state, action) => {
      const msg = action.payload;
      // Only add if it's for the current conversation
      if (msg && state.currentRecipientId) {
        const senderId = msg.senderId?._id || msg.senderId;
        const receiverId = msg.receiverId?._id || msg.receiverId;
        if (senderId === state.currentRecipientId || receiverId === state.currentRecipientId) {
          // Avoid duplicates
          const exists = state.currentMessages.some((m) => m._id === msg._id);
          if (!exists) {
            state.currentMessages = [...state.currentMessages, msg];
          }
        }
      }
    },
    incrementUnread: (state) => {
      state.unreadCount += 1;
    },
  },
  extraReducers: (builder) => {
    // Chat list
    builder
      .addCase(fetchChatList.pending, (state) => {
        state.listLoading = true;
      })
      .addCase(fetchChatList.fulfilled, (state, action) => {
        state.listLoading = false;
        state.chatList = action.payload;
      })
      .addCase(fetchChatList.rejected, (state, action) => {
        state.listLoading = false;
        state.error = action.payload;
      });

    // Fetch messages
    builder
      .addCase(fetchMessages.pending, (state) => {
        state.loading = true;
      })
      .addCase(fetchMessages.fulfilled, (state, action) => {
        state.loading = false;
        const { messages, skip, receiverId } = action.payload;
        state.currentRecipientId = receiverId;
        if (skip === 0) {
          state.currentMessages = messages.reverse();
        } else {
          // Prepend older messages
          const reversed = messages.reverse();
          state.currentMessages = [...reversed, ...state.currentMessages];
        }
        state.hasMoreMessages = messages.length >= 50;
      })
      .addCase(fetchMessages.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      });

    // Send text
    builder
      .addCase(sendTextMessage.pending, (state) => {
        state.sending = true;
      })
      .addCase(sendTextMessage.fulfilled, (state, action) => {
        state.sending = false;
        if (action.payload) {
          state.currentMessages = [...state.currentMessages, action.payload];
        }
      })
      .addCase(sendTextMessage.rejected, (state, action) => {
        state.sending = false;
        state.error = action.payload;
      });

    // Send media
    builder
      .addCase(sendMediaMessage.pending, (state) => {
        state.sending = true;
      })
      .addCase(sendMediaMessage.fulfilled, (state, action) => {
        state.sending = false;
        if (action.payload) {
          state.currentMessages = [...state.currentMessages, action.payload];
        }
      })
      .addCase(sendMediaMessage.rejected, (state, action) => {
        state.sending = false;
        state.error = action.payload;
      });

    // Mark read
    builder
      .addCase(markChatRead.fulfilled, (state, action) => {
        const recipientId = action.payload;
        state.chatList = state.chatList.map((c) => {
          const cId = c.userId || c._id;
          if (cId === recipientId) return { ...c, count: 0 };
          return c;
        });
      });

    // Delete message
    builder
      .addCase(deleteChatMessage.fulfilled, (state, action) => {
        const messageId = action.payload;
        state.currentMessages = state.currentMessages.filter((m) => m._id !== messageId);
      });

    // Unread count
    builder
      .addCase(fetchUnreadCount.fulfilled, (state, action) => {
        const data = action.payload;
        state.unreadCount = typeof data === 'number' ? data : data?.count || 0;
      });
  },
});

export const { resetChat, clearCurrentChat, addIncomingMessage, incrementUnread } = chatSlice.actions;
export default chatSlice.reducer;
