import { configureStore } from '@reduxjs/toolkit';
import { persistStore, persistReducer } from 'redux-persist';
import storage from 'redux-persist/lib/storage';
import { combineReducers } from '@reduxjs/toolkit';
import authSlice from './redux/slices/authSlice';
import postSlice from './redux/slices/postSlice';
import friendSlice from './redux/slices/friendSlice';
import chatSlice from './redux/slices/chatSlice';
import groupSlice from './redux/slices/groupSlice';
import notificationSlice from './redux/slices/notificationSlice';

const persistConfig = {
  key: 'friendlinq',
  storage,
  whitelist: ['auth'],
};

const rootReducer = combineReducers({
  auth: authSlice,
  posts: postSlice,
  friends: friendSlice,
  chat: chatSlice,
  groups: groupSlice,
  notifications: notificationSlice,
});

const persistedReducer = persistReducer(persistConfig, rootReducer);

export const store = configureStore({
  reducer: persistedReducer,
  middleware: (getDefaultMiddleware) =>
    getDefaultMiddleware({
      serializableCheck: {
        ignoredActions: ['persist/PERSIST', 'persist/REHYDRATE'],
      },
    }),
});

export const persistor = persistStore(store);
