import { nodeApi, dotnetApi, dotnetCustomerApi } from '../axios';
import { ENDPOINTS } from '../config';
import { postFormData } from '../helpers';

// Node.js endpoints use FormData POST; .NET endpoints use JSON
const friendService = {
  getFriendList: (params) => postFormData(nodeApi, ENDPOINTS.GET_FRIEND_LIST, params),
  getFriendCount: (params) => dotnetApi.get(ENDPOINTS.GET_FRIEND_COUNT, { params }),
  searchUser: (params) => postFormData(nodeApi, ENDPOINTS.SEARCH_USER, params),
  sendFriendRequest: (params) => postFormData(nodeApi, ENDPOINTS.SEND_FRIEND_REQUEST, params),
  acceptFriendRequest: (params) => postFormData(nodeApi, ENDPOINTS.ACCEPT_FRIEND_REQUEST, params),
  deleteFriend: (data) => dotnetApi.post(ENDPOINTS.DELETE_FRIEND, data),
  getSuggestions: (params) => dotnetApi.get(ENDPOINTS.GET_SUGGESTION, { params }),
  getNearby: (params) => dotnetCustomerApi.get(ENDPOINTS.GET_NEARBY, { params }),
  isFriend: (params) => dotnetCustomerApi.get(ENDPOINTS.IS_FRIEND, { params }),
  getOtherProfile: (params) => postFormData(nodeApi, ENDPOINTS.GET_OTHER_PROFILE, params),
};

export default friendService;
