import { createAsyncThunk } from '@reduxjs/toolkit';
import friendService from '../../api/services/friendService';

export const fetchFriends = createAsyncThunk(
  'friends/fetchFriends',
  async ({ skip = 0, limit = 20 }, { rejectWithValue }) => {
    try {
      const response = await friendService.getFriendList({ skip, limit });
      return { friends: response.data.data || [], skip };
    } catch (error) {
      return rejectWithValue(error.response?.data?.message || 'Failed to load friends');
    }
  }
);

