import { nodeApi, dotnetApi, dotnetCustomerApi } from '../axios';
import { ENDPOINTS } from '../config';
import { postFormData } from '../helpers';

// Node.js endpoints use FormData POST; .NET endpoints use JSON
const chatService = {
  sendMessage: (params) => postFormData(nodeApi, ENDPOINTS.SEND_MESSAGE, params),
  getMessages: (params) => postFormData(nodeApi, ENDPOINTS.GET_MESSAGES, params),
  sendMedia: (formData) => nodeApi.post(ENDPOINTS.SEND_MEDIA, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  deleteChat: (data) => dotnetApi.post(ENDPOINTS.DELETE_CHAT, data),
  getChatList: (params) => dotnetApi.get(ENDPOINTS.GET_CHAT_LIST, { params }),
  readChat: (data) => dotnetApi.post(ENDPOINTS.READ_CHAT, data),
  deleteAllChat: (data) => dotnetApi.post(ENDPOINTS.DELETE_ALL_CHAT, data),
  getUnreadCount: (params) => dotnetApi.get(ENDPOINTS.GET_UNREAD_COUNT, { params }),
  isChatSubscribed: (data) => dotnetCustomerApi.post(ENDPOINTS.IS_CHAT_SUBSCRIBED, data),
  processChatPayment: (data) => dotnetCustomerApi.post(ENDPOINTS.PROCESS_CHAT_PAYMENT, data),
};

export default chatService;
