import axios from 'axios';
import { NODE_API, DOTNET_API, DOTNET_CLIENT, DOTNET_CUSTOMER } from './config';

// Node.js API instance
export const nodeApi = axios.create({
  baseURL: NODE_API,
  timeout: 30000,
});

// .NET API instance
export const dotnetApi = axios.create({
  baseURL: DOTNET_API,
  timeout: 30000,
});

// .NET Client API instance
export const dotnetClientApi = axios.create({
  baseURL: DOTNET_CLIENT,
  timeout: 30000,
});

// .NET Customer API instance
export const dotnetCustomerApi = axios.create({
  baseURL: DOTNET_CUSTOMER,
  timeout: 30000,
});

// Auth interceptor — inject token into all requests
const addAuthInterceptor = (instance) => {
  instance.interceptors.request.use(
    (config) => {
      const token = localStorage.getItem('friendlinq_token');
      if (token) {
        config.headers.authorization = token;
        config.headers.accessToken = token;
      }
      return config;
    },
    (error) => Promise.reject(error)
  );

  instance.interceptors.response.use(
    (response) => response,
    (error) => {
      if (error.response && error.response.status === 401) {
        localStorage.removeItem('friendlinq_token');
        localStorage.removeItem('friendlinq_user');
        window.location.href = '/login';
      }
      return Promise.reject(error);
    }
  );
};

addAuthInterceptor(nodeApi);
addAuthInterceptor(dotnetApi);
addAuthInterceptor(dotnetClientApi);
addAuthInterceptor(dotnetCustomerApi);
