import { createSlice } from '@reduxjs/toolkit';
import {
  fetchNotifications, markNotificationRead, markAllRead, deleteNotification,
} from '../thunks/notificationThunks';

const initialState = {
  notifications: [],
  unreadCount: 0,
  loading: false,
  hasMore: true,
  error: null,
};

const notificationSlice = createSlice({
  name: 'notifications',
  initialState,
  reducers: {
    resetNotifications: () => initialState,
  },
  extraReducers: (builder) => {
    builder
      .addCase(fetchNotifications.pending, (state) => { state.loading = true; })
      .addCase(fetchNotifications.fulfilled, (state, action) => {
        state.loading = false;
        const { notifications, skip } = action.payload;
        if (skip === 0) {
          state.notifications = notifications;
        } else {
          state.notifications = [...state.notifications, ...notifications];
        }
        state.hasMore = notifications.length >= 30;
        state.unreadCount = state.notifications.filter((n) => !n.isRead).length;
      })
      .addCase(fetchNotifications.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      });

    builder
      .addCase(markNotificationRead.fulfilled, (state, action) => {
        const id = action.payload;
        state.notifications = state.notifications.map((n) =>
          n._id === id ? { ...n, isRead: true } : n
        );
        state.unreadCount = Math.max(0, state.unreadCount - 1);
      });

    builder
      .addCase(markAllRead.fulfilled, (state) => {
        state.notifications = state.notifications.map((n) => ({ ...n, isRead: true }));
        state.unreadCount = 0;
      });

    builder
      .addCase(deleteNotification.fulfilled, (state, action) => {
        const id = action.payload;
        const wasUnread = state.notifications.find((n) => n._id === id && !n.isRead);
        state.notifications = state.notifications.filter((n) => n._id !== id);
        if (wasUnread) state.unreadCount = Math.max(0, state.unreadCount - 1);
      });
  },
});

export const { resetNotifications } = notificationSlice.actions;
export default notificationSlice.reducer;
